export function getCountyStat(slug: string): CountyStat | undefined {
  return COUNTY_STATS[slug]
}

export function getCityStat(countySlug: string, citySlug: string): CityStat | undefined {
  return CITY_STATS[countySlug]?.find((c) => c.citySlug === citySlug)
}
